using Contoso.Scoring;

namespace Contoso.Scoring.Tests;

[TestClass]
public sealed class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calculator = new();

    // --- CalculatePercentage ---

    [TestMethod]
    [DataRow(7, 10, 70.0)]
    [DataRow(10, 10, 100.0)]
    [DataRow(0, 10, 0.0)]
    [DataRow(1, 3, 33.333333333333336)]
    public void CalculatePercentage_ValidInputs_ReturnsExpected(int correct, int total, double expected)
    {
        var result = _calculator.CalculatePercentage(correct, total);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void CalculatePercentage_Result_IsInValidRange()
    {
        var result = _calculator.CalculatePercentage(8, 10);

        Assert.IsInRange(result, 0.0, 100.0);
        Assert.IsGreaterThan(0.0, result);
        Assert.IsLessThan(100.0, result);
    }

    [TestMethod]
    public void CalculatePercentage_PerfectScore_ReturnsExactly100()
    {
        var result = _calculator.CalculatePercentage(10, 10);

        Assert.AreEqual(100.0, result);
    }

    [TestMethod]
    public void CalculatePercentage_ZeroCorrect_ReturnsExactly0()
    {
        var result = _calculator.CalculatePercentage(0, 10);

        Assert.AreEqual(0.0, result);
    }

    [TestMethod]
    public void CalculatePercentage_NegativeCorrect_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(-1, 10));
    }

    [TestMethod]
    public void CalculatePercentage_ZeroTotal_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(0, 0));
    }

    [TestMethod]
    public void CalculatePercentage_CorrectExceedsTotal_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(11, 10));
    }

    // --- GetGrade boundary tests ---

    [TestMethod]
    [DataRow(100.0, "A")]
    [DataRow(90.0, "A", DisplayName = "Boundary: A starts at 90")]
    [DataRow(89.99, "B", DisplayName = "Boundary: just below A")]
    [DataRow(80.0, "B", DisplayName = "Boundary: B starts at 80")]
    [DataRow(79.99, "C", DisplayName = "Boundary: just below B")]
    [DataRow(70.0, "C", DisplayName = "Boundary: C starts at 70")]
    [DataRow(69.99, "D", DisplayName = "Boundary: just below C")]
    [DataRow(60.0, "D", DisplayName = "Boundary: D starts at 60")]
    [DataRow(59.99, "F", DisplayName = "Boundary: just below D")]
    [DataRow(0.0, "F")]
    [DataRow(-5.0, "F")]
    public void GetGrade_AtBoundaries_ReturnsCorrectGrade(double percentage, string expected)
    {
        var grade = _calculator.GetGrade(percentage);

        Assert.AreEqual(expected, grade);
    }

    // --- NormalizeScore ---

    [TestMethod]
    public void NormalizeScore_MidRange_ReturnsValueInRange()
    {
        var result = _calculator.NormalizeScore(45.0, 100.0);

        Assert.IsInRange(result, 0.0, 100.0);
        Assert.AreEqual(45.0, result);
    }

    [TestMethod]
    public void NormalizeScore_ExceedsMax_CapsAt100()
    {
        var result = _calculator.NormalizeScore(120.0, 100.0);

        Assert.AreEqual(100.0, result);
        Assert.IsLessThan(101.0, result);
    }

    [TestMethod]
    public void NormalizeScore_ZeroRaw_ReturnsZero()
    {
        var result = _calculator.NormalizeScore(0.0, 50.0);

        Assert.AreEqual(0.0, result);
    }

    [TestMethod]
    public void NormalizeScore_AlwaysNonNegativeAndCapped()
    {
        var result = _calculator.NormalizeScore(75.0, 200.0);

        Assert.IsGreaterThan(-1.0, result);
        Assert.IsLessThan(101.0, result);
        Assert.IsInRange(result, 0.0, 100.0);
    }

    [TestMethod]
    public void NormalizeScore_NegativeRawScore_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(-1.0, 100.0));
    }

    [TestMethod]
    public void NormalizeScore_ZeroMaxRaw_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(50.0, 0.0));
    }

    [TestMethod]
    public void NormalizeScore_NegativeMaxRaw_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(50.0, -10.0));
    }
}

